const html = $input.first().json;
const config = $('2. Set — Config Values').item.json;

let rawHtml = typeof html === 'string' ? html : (html?.data || JSON.stringify(html));

if (!rawHtml || rawHtml.length < 100) {
  throw new Error('Page scrape returned no content. Check the URL and try again.');
}

let cleanText = rawHtml
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<!--[\s\S]*?-->/g, '')
  .replace(/<nav[\s\S]*?<\/nav>/gi, '')
  .replace(/<footer[\s\S]*?<\/footer>/gi, '')
  .replace(/<header[\s\S]*?<\/header>/gi, '')
  .replace(/<\/(div|p|li|h[1-6]|section|article)>/gi, '\n')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/\s{3,}/g, '\n\n')
  .trim()
  .substring(0, 3500);

return [{
  json: {
    pageContent: cleanText,
    pageUrl: config.pageUrl,
    currentHeadline: config.currentHeadline,
    pageName: config.pageName,
    conversionGoal: config.conversionGoal,
    targetAudience: config.targetAudience,
    submittedBy: config.submittedBy,
    today: config.today,
    sheetId: config.sheetId,
    sheetName: config.sheetName,
    recipientEmail: config.recipientEmail,
    senderName: config.senderName
  }
}];

const aiOutput = $input.first().json.output;
const pageData = $('4. Code — Clean Page Content').item.json;

if (!aiOutput || !Array.isArray(aiOutput) || aiOutput.length === 0) {
  throw new Error('GPT did not return headline data. Check OpenAI credentials.');
}

const sorted = [...aiOutput].sort((a, b) => (b.overallScore || 0) - (a.overallScore || 0));
const topHeadline = sorted[0];

// Return one item per headline
return aiOutput.map(h => ({
  json: {
    today: pageData.today,
    pageUrl: pageData.pageUrl,
    pageName: pageData.pageName,
    headlineNum: h.headlineNumber,
    framework: h.framework,
    headlineCopy: h.headlineCopy,
    clarityScore: h.clarityScore + ' out of 10',
    emotionalPull: h.emotionalPull + ' out of 10',
    specificity: h.specificity + ' out of 10',
    seoFit: h.seoFit + ' out of 10',
    overallScore: h.overallScore + ' out of 10',
    testPriority: h.testPriority,
    submittedBy: pageData.submittedBy,
    isLastRow: h.headlineNumber === 10,
    allHeadlines: h.headlineNumber === 10 ? aiOutput : [],
    currentHeadline: pageData.currentHeadline,
    conversionGoal: pageData.conversionGoal,
    targetAudience: pageData.targetAudience,
    recipientEmail: pageData.recipientEmail,
    senderName: pageData.senderName,
    sheetId: pageData.sheetId,
    sheetName: pageData.sheetName
  }
}));

const data = $('8. Code — Split Headlines for Sheets').item.json;
const allHeadlines = data.allHeadlines || [];

const sorted = [...allHeadlines].sort((a, b) => (b.overallScore || 0) - (a.overallScore || 0));
const testFirst = sorted.filter(h => h.testPriority === 'Test First');
const testSecond = sorted.filter(h => h.testPriority === 'Test Second');
const testThird = sorted.filter(h => h.testPriority === 'Test Third');
const lower = sorted.filter(h => h.testPriority === 'Lower Priority');

let body = 'Hello ' + data.senderName + ',\n\n';
body += 'Here are 10 scored headline variations for your landing page.\n\n';
body += 'Page: ' + data.pageName + '\n';
body += 'URL: ' + data.pageUrl + '\n';
body += 'Conversion goal: ' + data.conversionGoal + '\n';
body += 'Target audience: ' + data.targetAudience + '\n';
body += 'Current headline: ' + data.currentHeadline + '\n\n';
body += '============================================================\n\n';

const formatGroup = (headlines, label) => {
  if (headlines.length === 0) return '';
  let text = label + '\n\n';
  headlines.forEach(h => {
    text +=
      'Framework: ' + h.framework + '\n' +
      'Headline: ' + h.headlineCopy + '\n' +
      'Overall score: ' + h.overallScore + ' out of 10\n' +
      'Clarity: ' + h.clarityScore + ' | Emotional pull: ' + h.emotionalPull + ' | Specificity: ' + h.specificity + ' | SEO fit: ' + h.seoFit + '\n' +
      'Testing tip: ' + h.testingTip + '\n\n';
  });
  return text + '------------------------------------------------------------\n\n';
};

body += formatGroup(testFirst, 'TEST FIRST — Strongest headlines');
body += formatGroup(testSecond, 'TEST SECOND — Strong alternatives');
body += formatGroup(testThird, 'TEST THIRD — Good backups');
body += formatGroup(lower, 'LOWER PRIORITY — Use if above are tested');

body += 'HOW TO USE THESE HEADLINES\n\n';
body += '1. Start with the Test First headlines — run for at least 1000 visitors each\n';
body += '2. Measure click-through rate and conversion rate for each\n';
body += '3. Keep the winner and move to Test Second for further improvement\n';
body += '4. Replace your current headline: ' + data.currentHeadline + '\n\n';
body += 'All 10 headlines with full scores are saved in your Google Sheets Headline Tests tab.\n\n';
body += 'Best regards,\n' + data.senderName;

return [{
  json: {
    emailSubject: '10 Headline Variations Ready — ' + data.pageName + ' — ' + data.today,
    emailBody: body,
    recipientEmail: data.recipientEmail
  }
}];
